	registry := plugin.NewRegistry()
	if err := registerBuiltInPlugins(registry); err != nil {
		return err
	}

	dbPath, err := store.DefaultPath()
	if err != nil {
		return err
	}
	dataStore, err := store.Open(ctx, dbPath)
	if err != nil {
		return err
