func writeStringEnum(out *bytes.Buffer, valuesName string, schemaName string, exportValues bool, values []string) {
	constPrefix := "const"
	if exportValues {
		constPrefix = "export const"
	}
	fmt.Fprintf(out, "%s %s = [\n", constPrefix, valuesName)
	for _, value := range values {
		fmt.Fprintf(out, "  %s,\n", tsString(value))
	}
	fmt.Fprintf(out, "] as const;\n")
	fmt.Fprintf(out, "const %s = z.enum(%s);\n", schemaName, valuesName)
}

func tsString(value string) string {
	return "'" + strings.ReplaceAll(value, "'", "\\'") + "'"
}

func writeObjectSchema(out *bytes.Buffer, name string, fields []fieldSchema) {
	fmt.Fprintf(out, "const %s = z.object({\n", name)
	for _, field := range fields {
		schema := field.Schema
		if field.Optional {
			schema += ".optional()"
		}
		fmt.Fprintf(out, "  %s: %s,\n", field.Name, schema)
	}
	fmt.Fprintf(out, "});\n")
}

func schemaFields(value reflect.Type) ([]fieldSchema, error) {
	fields := make([]fieldSchema, 0, value.NumField())
	for i := 0; i < value.NumField(); i++ {
		field := value.Field(i)
		jsonName, optional, ok := jsonField(field)
		if !ok {
			continue
		}

		schema, err := zodSchema(field.Type)
		if err != nil {
			return nil, fmt.Errorf("%s.%s: %w", value.Name(), field.Name, err)
		}
		fields = append(fields, fieldSchema{
			Name:     jsonName,
			Optional: optional,
			Schema:   schema,
		})

